-- Program: Spy Fitness
-- Category: Celebrity-Style -> celebrity
-- Priority: Low
-- Durations: [4, 8], Sessions: [5, 6]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Spy Fitness',
    'Agile and strong: bodyweight mastery, speed, agility drills, and functional combat conditioning for peak versatility.',
    'celebrity',
    'intermediate',
    8,
    6,
    'full_body',
    ARRAY['Build cardiovascular endurance', 'Improve VO2 max', 'Improve athletic performance', 'Develop explosiveness', 'Build functional strength']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Spy Fitness - 4w 5x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    4,
    'Spy Fitness - 4w 5x/wk',
    'celebrity',
    5,
    60,
    ARRAY['Build cardiovascular endurance', 'Improve VO2 max', 'Improve athletic performance', 'Develop explosiveness', 'Build functional strength']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Spy Fitness'
ON CONFLICT DO NOTHING;

