  AND pv.duration_weeks = 8
  AND pv.sessions_per_week = 5
ON CONFLICT DO NOTHING;

-- Variant: Spy Fitness - 8w 6x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    8,
    'Spy Fitness - 8w 6x/wk',
    'celebrity',
    6,
    60,
    ARRAY['Build cardiovascular endurance', 'Improve VO2 max', 'Improve athletic performance', 'Develop explosiveness', 'Build functional strength']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Spy Fitness'
ON CONFLICT DO NOTHING;

